import sys

MOD = 1000000007

def read_ints():
    return map(int, sys.stdin.readline().split())

def read_string():
    return sys.stdin.readline().strip()

def main():
    R, C = read_ints()
    grid = [read_string() for _ in range(R)]

    dp = [[0] * C for _ in range(R)]
    dp[0][0] = 1

    for r in range(R):
        for c in range(C):
            if grid[r][c] == '#':
                dp[r][c] = 0
            elif r > 0:
                dp[r][c] += dp[r-1][c]
            if c > 0:
                dp[r][c] += dp[r][c-1]
            dp[r][c] %= MOD

    print(dp[R-1][C-1])

if __name__ == "__main__":
    main()
