import sys

def count_paths(grid):
    MOD = 1000000007
    R, C = len(grid), len(grid[0])
    dp = [[0] * C for _ in range(R)]

    for i in range(R):
        if grid[i][0] == '#':
            break
        dp[i][0] = 1

    for j in range(C):
        if grid[0][j] == '#':
            break
        dp[0][j] = 1

    for i in range(1, R):
        for j in range(1, C):
            if grid[i][j] == '#':
                continue
            dp[i][j] = (dp[i-1][j] + dp[i][j-1]) % MOD

    return dp[R-1][C-1]

def main():
    R, C = map(int, input().split())
    grid = [input() for _ in range(R)]
    print(count_paths(grid))

if __name__ == "__main__":
    main()
