import sys

def count_subsets(values, target):
    MOD = 1000000007
    dp = [[0] * (target + 1) for _ in range(len(values) + 1)]
    dp[0][0] = 1

    for i in range(1, len(values) + 1):
        for j in range(target + 1):
            if j < values[i - 1]:
                dp[i][j] = dp[i - 1][j]
            else:
                dp[i][j] = (dp[i - 1][j] + dp[i - 1][j - values[i - 1]]) % MOD

    return dp[-1][-1]

def main():
    C, T = map(int, sys.stdin.readline().split())
    values = list(map(int, sys.stdin.readline().split()))
    result = count_subsets(values, T)
    print(result)

if __name__ == "__main__":
    main()
