import sys

def min_partition_diff(nums):
    total_sum = sum(nums)
    n = len(nums)
    dp = [[False] * (total_sum + 1) for _ in range(n + 1)]
    dp[0][0] = True
    for i in range(1, n + 1):
        for j in range(total_sum + 1):
            if j < nums[i - 1]:
                dp[i][j] = dp[i - 1][j]
            else:
                dp[i][j] = dp[i - 1][j] or dp[i - 1][j - nums[i - 1]]
    max_sum = 0
    for j in range(total_sum // 2, -1, -1):
        if dp[n][j]:
            max_sum = j
            break
    return abs(total_sum - 2 * max_sum)

