import sys

MOD = 1000000007

def count_paths(grid):
    R, C = len(grid), len(grid[0])
    dp = [[0] * C for _ in range(R)]

    dp[0][0] = 1
    for r in range(R):
        for c in range(C):
            if grid[r][c] == '.':
                if r > 0:
                    dp[r][c] += dp[r-1][c]
                if c > 0:
                    dp[r][c] += dp[r][c-1]
                dp[r][c] %= MOD

    return dp[R-1][C-1]

