### Worst-Case/Adversarial Inputs
1. Grid with a single row or column, where the cell at the start or end is blocked.
2. Grid with all cells blocked except for the start and end cells.
3. Grid with a large number of rows and columns, where the blocked cells are randomly distributed.

### Corrected Python Program
```python
import sys

MOD = 1000000007

def count_paths(grid):
    R, C = len(grid), len(grid[0])
    dp = [[0] * C for _ in range(R)]

    # Initialize the first cell as 1 if it's free
    dp[0][0] = 1

    # Fill the first row
    for c in range(1, C):
        if grid[0][c] == '.':
            dp[0][c] = dp[0][c-1]
        else:
            dp[0][c] = 0
        dp[0][c] %= MOD

    # Fill the first column
    for r in range(1, R):
        if grid[r][0] == '.':
            dp[r][0] = dp[r-1][0]
        else:
            dp[r][0] = 0
        dp[r][0] %= MOD

    # Fill the rest of the grid
    for r in range(1, R):
        for c in range(1, C):
            if grid[r][c] == '.':
                dp[r][c] = (dp[r-1][c] + dp[r][c-1]) % MOD
            else:
                dp[r][c] = 0

    return dp[R-1][C-1]

def main():
    R, C = map(int, sys.stdin.readline().split())
    grid = [sys.stdin.readline().strip() for _ in range(R)]
    print(count_paths(grid))

if __name__ == "__main__":
    main()
