import sys

def longest_increasing_subsequence(numbers):
    if not numbers:
        return 0

    dp = [1] * len(numbers)

    for i in range(1, len(numbers)):
        for j in range(i):
            if numbers[i] > numbers[j]:
                dp[i] = max(dp[i], dp[j] + 1)

    return max(dp)

def main():
